// scale_video.c - تحجيم وتحويل صيغ الصور باستخدام libswscale
#include <libswscale/swscale.h>
#include <stdio.h>

int main(void) {
    // تحويل من 1920x1080 YUV420P إلى 1280x720 RGB24
    struct SwsContext *sws = sws_getContext(
        1920, 1080, AV_PIX_FMT_YUV420P,
        1280, 720, AV_PIX_FMT_RGB24,
n        SWS_BILINEAR, NULL, NULL, NULL
    );

    if (!sws) {
        fprintf(stderr, "فشل إنشاء SwsContext\n");
        return 1;
    }

    // ملء frame وهم بلون أحمر
    int src_stride[1] = {1920 * 3};  // YUV420P: width * 3 bytes per row
    uint8_t *src_data[3] = {0};
    memset(src_data[0], 0, 1920 * 1080);
    memset(src_data[1], 128, 1920 * 1080 / 4);  // U
    memset(src_data[2], 255, 1920 * 1080 / 4);  // V

    int dst_stride[1] = {1280 * 3};   // RGB24: width * 3 bytes per row
    uint8_t dst_data[1280 * 720 * 3];
    memset(dst_data, 0, sizeof(dst_data));

    // تحويل
    sws_scale(sws,
        (const uint8_t *const *)src_data, src_stride,
        0, 1080,
        dst_data, dst_stride
    );
    printf("تم تحويل الصورة بنجاح\n");

    sws_freeContext(&sws);
    return 0;
}

